c\\)&quot;;\r\nmso-ascii-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;mso-hansi-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;\">إِلَيْهَا</span></b><span dir=\"LTR\"></span><span dir=\"LTR\"></span><span lang=\"AR-SA\" dir=\"LTR\" style=\"font-size:\r\n14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;mso-ascii-theme-font:\r\nmajor-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;mso-hansi-theme-font:major-bidi;\r\nmso-bidi-font-family:&quot;Times New Roman&quot;\"><span dir=\"LTR\"></span><span dir=\"LTR\"></span>\r\n</span><b><span lang=\"AR-SA\" style=\"font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;\r\nmso-ascii-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;mso-hansi-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;\">مُنْذُ</span></b><span dir=\"LTR\"></span><span dir=\"LTR\"></span><span lang=\"AR-SA\" dir=\"LTR\" style=\"font-size:\r\n14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;mso-ascii-theme-font:\r\nmajor-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;mso-hansi-theme-font:major-bidi;\r\nmso-bidi-font-family:&quot;Times New Roman&quot;\"><span dir=\"LTR\"></span><span dir=\"LTR\"></span>\r\n</span><b><span lang=\"AR-SA\" style=\"font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;\r\nmso-ascii-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;mso-hansi-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;\">خَلْقِهَا</span></b><span dir=\"LTR\"></span><span dir=\"LTR\"></span><b><span lang=\"IN\" dir=\"LTR\" style=\"font-family:\r\n&quot;LPMQ Isep Misbah&quot;;mso-bidi-font-family:&quot;LPMQ Isep Misbah&quot;;mso-ansi-language:\r\nIN\"><span dir=\"LTR\"></span><span dir=\"LTR\"></span>) </span></b><span lang=\"EN-US\" dir=\"LTR\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">».</span><b><span lang=\"AR-SA\" style=\"font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;mso-ascii-font-family:\r\n&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;mso-hansi-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;\">زبدة</span></b><span dir=\"LTR\"></span><span dir=\"LTR\"></span><span lang=\"AR-SA\" dir=\"LTR\" style=\"font-size:\r\n14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;mso-ascii-theme-font:\r\nmajor-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;mso-hansi-theme-font:major-bidi;\r\nmso-bidi-font-family:&quot;Times New Roman&quot;\"><span dir=\"LTR\"></span><span dir=\"LTR\"></span>\r\n</span><b><span lang=\"AR-SA\" style=\"font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;\r\nmso-ascii-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;mso-hansi-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;\">الواعظين</span></b><span dir=\"LTR\"></span><span dir=\"LTR\"></span><span lang=\"IN\" dir=\"LTR\" style=\"font-size:\r\n14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;mso-ascii-theme-font:\r\nmajor-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;mso-hansi-theme-font:major-bidi;\r\nmso-bidi-font-family:&quot;Times New Roman&quot;;mso-ansi-language:IN\"><span dir=\"LTR\"></span><span dir=\"LTR\"></span>(<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"line-height:150%\"><span lang=\"EN-US\" style=\"font-size:\r\n14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;mso-ascii-theme-font:\r\nmajor-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;mso-hansi-theme-font:major-bidi;\r\nmso-bidi-font-family:&quot;Times New Roman&quot;\">&nbsp;</span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><i><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">\"Sesungguhnya\r\nAllah tidak menciptakan makhluk yang paling dibenci daripada dunia.Dan\r\nsesungguhnya Allah tidak melihatnya semenjak Allah menciptakannya.\"<o:p></o:p></span></i></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><i><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\"><br></span></i></p><p style=\"text-align:justify;line-height:150%;\r\ndirection:rtl;unicode-bidi:embed\" class=\"\"><b><span lang=\"AR-SA\" style=\"font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;\r\nmso-ascii-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;mso-hansi-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;\">عَنْ\r\nجَابِرِ بْنِ عَبْدِ اللَّهِ ﷺ أَنَّهُ قَالَ: كُنْتُ مَعَ رَسُولِ اللَّهِ ﷺ إِذْ\r\nأَتَاهُ رَجُلٌ أَبْيَضُ الْوَجْهِ حَسَنُ الشَّعْرِ أَبيضُ الثَّيَابِ، فَقَالَ: السَّلَامُ\r\nعَلَيْكَ يَا رَسُولَ اللَّهِ، مَا الدُّنْيَا؟ قَالَ: «كَحُلْمِ النَّائِهِ»، قَالَ:\r\nوَمَا الْآخِرَةُ؟ قَالَ: «فَرِيقٌ فِي الْجَنَّةِ، وَفَرِيقٌ فِي السَّعِيرِ»، قَالَ:\r\nفَمَا الْجَنَّةُ؟ قَالَ: «بَدَلُ الدُّنْيَا لِتَارِكِهَا، فَإِنَّ ثَمَنَ الْجَنَّةِ\r\nتَرْكُ الدُّنْيَا، قَالَ: فَمَا جَهَنَّمُ؟ قَالَ: «بَدَلُ الدُّنْيَا لِطَالِبِهَا»،\r\nقَالَ: فَمَا خَيْرُ هَذِهِ الْأُمَّةِ؟ قَالَ: «الَّذِي يَعْمَلُ بِطَاعَةِ اللَّهِ\r\nتَعَالَى»، قَالَ: فَكَيْفَ يَكُوْنُ الرَّجُلُ فِيْهَا؟ قَالَ: «مُشَمِّرًا كَطَالِبِ\r\nالْقَافِلَةِ»، قَالَ: فَكَمِ الْقَرَارُ فِيْهَا؟ قَالَ: كَقَدْرِ الْمُتَخَلَّفِ\r\nعَنِ الْقَافِلَةِ»، قَالَ: فَكَمْ مَا بَيْنَ الدُّنْيَا وَالآخِرَةِ؟ قَالَ: «غَمْضَةُ\r\nعَيْنٍ»، قَالَ جَابِرٌ: فَذَهَبَ الرَّجُلُ فَلَمْ نَرَهُ. فَقَالَ رَسُوْلُ اللَّهِ\r\nﷺ «هَذَا جَبْرَائِيلُ أَتَاكُمْ لِيُزَهْدَكُمْ فِي الدُّنْيَا وَيُرَغِبَكُمْ فِي\r\nالآخِرَةِ». (زبدة الواعظين)</span></b></p><p class=\"MsoNormal\" align=\"right\" style=\"text-align:right;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">&nbsp;</span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Dari\r\nsahabat Jabir bin Abdullah berkata: Sewaktu saya bersama Rasulullah, tiba-tiba\r\ndatang kepadanya seorang lelaki yang putih wajah-nya, bagus rambutnya dan putih\r\npakaiannya,<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">la\r\nberkata: \"Assalamu\'alaika Yâ Rasûlullâh, apakah dunia itu?\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Nabi\r\nmenjawab: \"Bagaikan mimpinya orang tidur.\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Lalu ia\r\nbertanya: \"Dan apakah akhirat itu?\"</span><span lang=\"IN\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;;\r\nmso-ansi-language:IN\"><o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Nabi\r\nmenjawab: \"Sebagian di surga dan sebagian di neraka.\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Lalu ia\r\nbertanya: \"Lalu apakah surga itu?\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Nabi\r\nmenjawab: \"Gantinya dunia bagi orang yang sanggup meninggalkannya, karena\r\nharganya surga adalah meninggalkan dunia.\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Lalu ia\r\nbertanya: \"Lalu apakah Jahannam itu?\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Nabi\r\nmenjawab: \"Gantinya dunia bagi orang yang mencarinya.\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Lalu ia\r\nbertanya: \"Lalu siapakah yang menjadi sebaik-baik umat ini?\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Nabi\r\nmenjawab: \"Orang yang taat kepada Allah (ketika di dunia).\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Lalu ia\r\nbertanya: \"Bagaimana laki-laki itu di dalamnya?\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Nabi\r\nmenjawab: \"Layaknya orang yang bergegas mengejar qâfilah(rombongan).\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Lalu ia\r\nbertanya: \"Berapa lama tinggal di dunia?\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Nabi\r\nmenjawab: \"Seperti lamanya orang yang tertinggal dari\r\nqâfilah-qafilah.\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">lalu ia\r\nbertanya: \"lalu berapa lama antara dunia dan akhirat?\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Nabi\r\nmenjawab: \"Sekejap mata.\"<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Sahabat\r\nJabir berkata: Lalu laki-laki itu pergi dan kami tidak melihatnya (lagi).<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Lalu\r\nRasulullah bersabda: \"Itu tadi Jibril, datang untuk men-zuhûd-kan kalian\r\ndari dunia, dan membuat kalian cinta pada akhirat.\"</span><span lang=\"IN\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;;\r\nmso-ansi-language:IN\"><o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"IN\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;;\r\nmso-ansi-language:IN\">&nbsp;</span></p><p class=\"MsoNormal\" align=\"center\" style=\"text-align:center;line-height:150%\"><b><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Ma\'asyiral\r\nhadiriin jama\'ah jum\'at Rahimakumullah</span></b><b><span lang=\"IN\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;;\r\nmso-ansi-language:IN\"><o:p></o:p></span></b></p><p class=\"MsoNormal\" align=\"center\" style=\"text-align:center;line-height:150%\"><b><span lang=\"IN\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;;\r\nmso-ansi-language:IN\">&nbsp;</span></b></p><p class=\"MsoNormal\" style=\"text-indent:36.0pt;line-height:150%\"><span lang=\"EN-US\" style=\"font-size:14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;\">Sayyidinâ\r\nAll bin Abi Thalib Karramâllahu Wajhah memberi gambaran dunia ini seperti bayang-bayang.\r\nApabila kita lari daripadanya, artinya kita selalu berbakti dan bertakwa kepada\r\nAllah, maka dunia itu akan dipersiapkan untuk kita.Tetapi apabila kita selalu\r\nberusaha mengejarnya, maka dunia itu akan sulit kita peroleh, begitu beliau\r\nberkata:</span><span lang=\"IN\" style=\"font-size:14.0pt;line-height:150%;\r\nmso-ascii-font-family:&quot;Times New Roman&quot;;mso-ascii-theme-font:major-bidi;\r\nmso-hansi-font-family:&quot;Times New Roman&quot;;mso-hansi-theme-font:major-bidi;\r\nmso-bidi-font-family:&quot;Times New Roman&quot;;mso-ansi-language:IN\"><o:p></o:p></span></p><p class=\"MsoNormal\" dir=\"RTL\" style=\"text-align:justify;line-height:150%;\r\ndirection:rtl;unicode-bidi:embed\"><span lang=\"EN-US\" dir=\"LTR\" style=\"font-size:\r\n14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;mso-ascii-theme-font:\r\nmajor-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;mso-hansi-theme-font:major-bidi;\r\nmso-bidi-font-family:&quot;Times New Roman&quot;\">\"</span><b><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:150%;font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;\r\nmso-ascii-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;mso-hansi-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;\">إِنَّ</span></b><span dir=\"LTR\"></span><span dir=\"LTR\"></span><span lang=\"AR-SA\" dir=\"LTR\" style=\"font-size:\r\n14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;mso-ascii-theme-font:\r\nmajor-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;mso-hansi-theme-font:major-bidi;\r\nmso-bidi-font-family:&quot;Times New Roman&quot;\"><span dir=\"LTR\"></span><span dir=\"LTR\"></span>\r\n</span><b><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:150%;font-family:\r\n&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;mso-ascii-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;\r\nmso-hansi-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;\">الدُّنْيَا</span></b><span dir=\"LTR\"></span><span dir=\"LTR\"></span><span lang=\"AR-SA\" dir=\"LTR\" style=\"font-size:\r\n14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;mso-ascii-theme-font:\r\nmajor-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;mso-hansi-theme-font:major-bidi;\r\nmso-bidi-font-family:&quot;Times New Roman&quot;\"><span dir=\"LTR\"></span><span dir=\"LTR\"></span>\r\n</span><b><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:150%;font-family:\r\n&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;mso-ascii-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;\r\nmso-hansi-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;\">ظِلٍّ</span></b><span dir=\"LTR\"></span><span dir=\"LTR\"></span><span lang=\"AR-SA\" dir=\"LTR\" style=\"font-size:\r\n14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;mso-ascii-theme-font:\r\nmajor-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;mso-hansi-theme-font:major-bidi;\r\nmso-bidi-font-family:&quot;Times New Roman&quot;\"><span dir=\"LTR\"></span><span dir=\"LTR\"></span>\r\n</span><b><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:150%;font-family:\r\n&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;mso-ascii-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;\r\nmso-hansi-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;\">إِذَا</span></b><span dir=\"LTR\"></span><span dir=\"LTR\"></span><span lang=\"AR-SA\" dir=\"LTR\" style=\"font-size:\r\n14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;mso-ascii-theme-font:\r\nmajor-bidi;mso-hansi-font-family:&quot;Times New Roman&quot;;mso-hansi-theme-font:major-bidi;\r\nmso-bidi-font-family:&quot;Times New Roman&quot;\"><span dir=\"LTR\"></span><span dir=\"LTR\"></span>\r\n</span><b><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:150%;font-family:\r\n&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;mso-ascii-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;;\r\nmso-hansi-font-family:&quot;LPMQ Isep Misbah \\(Arabic\\)&quot;\">فَرَرْتَ</span></b><span dir=\"LTR\"></span><span dir=\"LTR\"></span><span lang=\"AR-SA\" dir=\"LTR\" style=\"font-size:\r\n14.0pt;line-height:150%;mso-ascii-font-family:&quot;Times New Roman&quot;;mso-ascii-theme-font:\r\nmajor-bidi;mso-